#define IN_RANGE(x, min, max)   ((x)>= (min) && (x)<= (max))
#define CLAMP_RANGE(x, min, max) x = (x<(min)) ? min : ((x>(max)) ? max : x )
#define MIN(a, b) ((a)<= (b) ? (a) : (b))

void dynproc_kernel(
                int iteration, 
                int *gpuWall,
                int *gpuSrc,
                int *gpuResults,
                int cols, 
                int rows,
                int startStep,
                int border,
                int bx)
{

        int prev[BLOCK_SIZE];
        int result[BLOCK_SIZE];

	int tx=omp_get_thread_num();

	int small_block_cols = BLOCK_SIZE-iteration*HALO*2;

        int blkX = small_block_cols*bx-border;
        int blkXmax = blkX+BLOCK_SIZE-1;

	int xidx = blkX+tx;

        int validXmin = (blkX < 0) ? -blkX : 0;
        int validXmax = (blkXmax > cols-1) ? BLOCK_SIZE-1-(blkXmax-cols+1) : BLOCK_SIZE-1;

        int W = tx-1;
        int E = tx+1;

        W = (W < validXmin) ? validXmin : W;
        E = (E > validXmax) ? validXmax : E;

        bool isValid = IN_RANGE(tx, validXmin, validXmax);

	if(IN_RANGE(xidx, 0, cols-1)){
            prev[tx] = gpuSrc[xidx];
	}
	#pragma omp barrier
        bool computed;
        for (int i=0; i<iteration ; i++){ 
            computed = false;
            if( IN_RANGE(tx, i+1, BLOCK_SIZE-i-2) &&  \
                  isValid){
                  computed = true;
                  int left = prev[W];
                  int up = prev[tx];
                  int right = prev[E];
                  int shortest = MIN(left, up);
                  shortest = MIN(shortest, right);
                  int index = cols*(startStep+i)+xidx;
                  result[tx] = shortest + gpuWall[index];

            }
            #pragma omp barrier
            if(i==iteration-1)
                break;
            if(computed)	 
                prev[tx]= result[tx];
	    #pragma omp barrier 
      }

      if (computed){
          gpuResults[xidx]=result[tx];		
      }
}

int calc_path(int *gpuWall, int *gpuResult[2], int rows, int cols, \
	 int pyramid_height, int blockCols, int borderCols)
{
        int src = 1, dst = 0;
	for (int t = 0; t < rows-1; t+=pyramid_height) {
            int temp = src;
            src = dst;
            dst = temp;

            #pragma omp parallel num_threads(BLOCK_SIZE)
            {
                int bx = omp_get_thread_num() / BLOCK_SIZE;
                if (bx < blockCols) {
                    dynproc_kernel(
                        MIN(pyramid_height, rows-t-1), 
                        gpuWall, gpuResult[src], gpuResult[dst],
                        cols,rows, t, borderCols, bx);
                }
            }
	}
        return dst;
}

