// OpenMP version of srad_cuda_1
void srad_1(float *E_C, float *W_C, float *N_C, float *S_C,
            float *J, float *C, int cols, int rows, float q0sqr)
{
    #pragma omp parallel for collapse(2)
    for (int i = 0; i < rows; i++) {
        for (int j = 0; j < cols; j++) {
            int k = i * cols + j;
            float jc = J[k];

            // Get neighbor indices with boundary handling
            int iN = (i == 0) ? 0 : i - 1;
            int iS = (i == rows - 1) ? rows - 1 : i + 1;
            int jW = (j == 0) ? 0 : j - 1;
            int jE = (j == cols - 1) ? cols - 1 : j + 1;

            float n = J[iN * cols + j] - jc;
            float s = J[iS * cols + j] - jc;
            float w = J[i * cols + jW] - jc;
            float e = J[i * cols + jE] - jc;

            float g2 = (n * n + s * s + w * w + e * e) / (jc * jc);
            float l = (n + s + w + e) / jc;

            float num = (0.5 * g2) - ((1.0 / 16.0) * (l * l));
            float den = 1 + (0.25 * l);
            float qsqr = num / (den * den);

            den = (qsqr - q0sqr) / (q0sqr * (1 + q0sqr));
            float c = 1.0 / (1.0 + den);

            if (c < 0) c = 0;
            else if (c > 1) c = 1;

            C[k] = c;
            E_C[k] = e;
            W_C[k] = w;
            S_C[k] = s;
            N_C[k] = n;
        }
    }
}

// OpenMP version of srad_cuda_2
void srad_2(float *E_C, float *W_C, float *N_C, float *S_C,
            float *J, float *C, int cols, int rows, float lambda, float q0sqr)
{
    #pragma omp parallel for collapse(2)
    for (int i = 0; i < rows; i++) {
        for (int j = 0; j < cols; j++) {
            int k = i * cols + j;

            // Get neighbor indices with boundary handling
            int iS = (i == rows - 1) ? rows - 1 : i + 1;
            int jE = (j == cols - 1) ? cols - 1 : j + 1;

            float cc = C[k];
            float cn = cc;
            float cs = C[iS * cols + j];
            float cw = cc;
            float ce = C[i * cols + jE];

            float d_sum = cn * N_C[k] + cs * S_C[k] + cw * W_C[k] + ce * E_C[k];

            J[k] = J[k] + 0.25 * lambda * d_sum;
        }
    }
}

